--- 请求农场信息
function ModelFarm:OnFarmInfoReq(activityId,playerId)
	local pb = LProtoHelper.CreateProto(LProtoIds.HappyFarmInfoReq)
	pb.activityId = activityId
	pb.target = playerId
	SendMessage(pb,LProtoIds.HappyFarmInfoReq)
end
--种植作物
function ModelFarm:OnHappyFarmPlantReq(activityId,farmLand)
	if not self:IsOpenActivity(activityId,true) then return end
	local pb = LProtoHelper.CreateProto(LProtoIds.HappyFarmPlantReq)
	pb.activityId = activityId
	for _, landInfo in pairs(farmLand or {}) do
		if landInfo.index and landInfo.seed then
			local farmLandObj = LProtoHelper.CreateProto(LProtoIds.FarmLandObj)
			farmLandObj.index = landInfo.index
			farmLandObj.seed = landInfo.seed
			table.insert(pb.lands,farmLandObj)
		end	
	end
	SendMessage(pb,LProtoIds.HappyFarmPlantReq)
end
--批量种植
function ModelFarm:OnHappyFarmFastPlantReq(activityId,count,seedId)
	if not self:IsOpenActivity(activityId,true) then return end
	local pb = LProtoHelper.CreateProto(LProtoIds.HappyFarmFastPlantReq)
	pb.activityId = activityId
	for i = 1, count do
		local farmLandObj = LProtoHelper.CreateProto(LProtoIds.FarmLandObj)
		farmLandObj.index = 1
		farmLandObj.seed = seedId
		table.insert(pb.lands,farmLandObj)
	end
	SendMessage(pb,LProtoIds.HappyFarmFastPlantReq)
end

