--收菜、偷菜
function ModelFarm:OnHappyFarmPickCropsReq(activityId,type,tarPlayerId,lands)
	if type==1 and not self:IsOpenActivity(activityId,true) then return end
	local pb = LProtoHelper.CreateProto(LProtoIds.HappyFarmPickCropsReq)
	pb.activityId = activityId
	pb.type = type-- 0-收菜 1-偷菜
