function ModelFarm:IsOpenActivity(activityId,tips)
	local actData = gModelActivity:GetActivityBySid(activityId)
	local isOpen = actData.endTime > GetTimestamp()
	if not isOpen and tips then
		GF.ShowMessage(ccClientText(14301))
	end
	return isOpen
end

function ModelFarm:OnHappyFarmInfoResp(pb)
	---@type StructFarm
	local farmData = self.farmList[pb.target]
	if not farmData then farmData = StructFarm:New() end
	farmData:CreateByPb(pb)
	self.farmList[pb.target] = farmData
	FireEvent(EventNames.FARM_INFO_UPDATE,pb.target)
end

function ModelFarm:OnUpdateFarmInfo(pb)
	---@type StructFarmLand
	local farmInfo = self.farmLandList[pb.index]
	if not farmInfo then farmInfo = StructFarmLand:New() end
	farmInfo:CreateByPb(pb)
	self.farmLandList[pb.index] = farmInfo
end

function ModelFarm:OnHappyFarmPickCropsResp(pb)
	local playerId = gModelPlayer:GetPlayerId()
	---@type StructFarm
	local lands = {}
	if pb.type == 1 then --偷菜
		local farmData = self.farmList[playerId]
		farmData.stealingNum = pb.stealingNum
		for i, fail in ipairs(pb.failureResult) do table.insert(lands,{landIdx = fail.index,crop= fail.crop}) end
	end
	for i, succ in ipairs(pb.successResult) do table.insert(lands,{landIdx = succ.index,crop= succ.crop}) end

	FireEvent(EventNames.FARM_HARVEST_RESULIT,{lands = lands,pb = pb})
end
function ModelFarm:OnPatrolDogResp(pb)
	local playerId = gModelPlayer:GetPlayerId()
	---@type StructFarm
	local farmData = self.farmList[playerId]
	farmData.patrolDogTime = pb.patrolDogTime
	FireEvent(EventNames.FARM_DOGTIME_UPDATE,farmData.patrolDogTime>GetTimestamp())
end

function ModelFarm:OnHappyFarmRecordResp(pb)
	self.farmRecordList = {}
	for _, value in ipairs(pb.farmRecords) do
		---@type StructFarmRecord
		local farmRecord = StructFarmRecord:New()
		farmRecord:CreateByPb(value)
		table.insert(self.farmRecordList,farmRecord)
	end
	FireEvent(EventNames.FARM_RECORD_UPDATE)
end

function ModelFarm:OnHappyFarmLandListResp(pb)
	self.nearbyFarmList = {}
	local playerId = gModelPlayer:GetPlayerId()
	for _, value in ipairs(pb.farms) do
		if value.playerInfo.playerId ~= playerId then
			local nearFarm = StructNearbyFarm.CreateNearbyFarmObj(value)
			table.insert(self.nearbyFarmList,nearFarm)
		end
	end
	self.nearRefresh = pb.refresh
	self.nextTime = pb.nextTime
	if pb.refresh then
		self.nextTime = GetTimestamp()+self:GetStealingCD(pb.activityId)
		GF.ShowMessage(ccClientText(45957))
	end
	FireEvent(EventNames.FARM_NEARBY_UPDATE)
end
function ModelFarm:GetStealingCD(activityId)
	if not self.stealingCD then
		local activCfg = gModelActivity:GetWebActivityDataById(activityId)
		self.stealingCD = activCfg.config.stealingCd
	end
	return self.stealingCD
end

