function ModelFarm:OpenCommonTips(pb)
	local mainCfg = gModelActivity:GetWebActivityDataById(pb.activityId)
	local scoreId = mainCfg and mainCfg.config.itemId
	local success = pb.successResult
	local failure = pb.failureResult
	local isSuccess = false
	local isFail = false
	local succCropStr = ""
	local succScoreStr = ""
	local succScoreNum = 0
	local failStr = ""
	for i, succ in ipairs(success) do
		local str = gModelItem:GetNameByRefId(succ.crop).."*"..succ.cropNum
		if i==1 then 
			succCropStr = str
		else
			succCropStr = succCropStr.."、"..str
		end
		succScoreNum = succScoreNum+(succ.loseScore or 0)
		isSuccess = true
	end
	succScoreStr = gModelItem:GetNameByRefId(scoreId).."*"..succScoreNum

	local scoreNum = 0
	for i, fail in ipairs(failure) do
		scoreNum = scoreNum+(fail.loseScore or 0)
		isFail = true
	end
	failStr = gModelItem:GetNameByRefId(scoreId).."*"..scoreNum
	
	
	local id = 0
	local param = {}
	if isSuccess and isFail then --部分成功
		-- 本次已偷取[作物名称+数量]，已转化为[积分名称*数量]，您的偷菜行为被[目标玩家]的狗抓到了，已掉落[农场积分名称*数量]
		id = 470303
		local targetRoleInfo = self.farmList[pb.target].roleInfo
		param = {succCropStr,succScoreStr,targetRoleInfo.name,failStr}
	elseif isSuccess and not isFail then--全部成功
		--“本次已偷取作物[名称*数量]，已转化为积分[名称*数量]”，
		id =470302
		param = {succCropStr,succScoreStr}
	elseif not isSuccess and isFail then--全部失败
		--您的偷菜行为被[目标玩家] 的狗抓到了，已掉落[农场积分名称*数量]”
		id = 470304
		local targetRoleInfo = self.farmList[pb.target].roleInfo
		param = {targetRoleInfo.name,failStr}
	end

	if id == 0 then return end
	local func = function()
		if pb.rewardInfo and pb.rewardInfo.items[1] then gModelDraconic:ShowComReward(pb.rewardInfo) end
	end
	gModelGeneral:OpenUIOrdinTips({refId = id,func = func, para = param})
end	
--剩余偷取次数
function ModelFarm:GetFarmStealNum(activityId,playerId)
	local activityCfg = gModelActivity:GetWebActivityDataById(activityId)
	if activityCfg and activityCfg.config then 
		if not playerId then playerId = gModelPlayer:GetPlayerId() end
		local farmInfo = self.farmList[playerId]
		if farmInfo then 
			return activityCfg.config.stealingNum - farmInfo.stealingNum
		end
	end
	return 0
end

--空闲/成熟地块
function ModelFarm:GetFarmLands(playerId,isNull)
	---@type StructFarm
	local farmData = self:GetFarmDataByPlayerId(playerId)
	local list = {}
	for Index = 1, ModelFarm.MaxLandNum do
		local land = farmData.lands[Index]
		if isNull and not land then table.insert(list,Index) end
		if not isNull and land and land:IsMatureCrop() then table.insert(list,Index) end
	end
	return #list,list
end
--獲取作物配置信息
function ModelFarm:GetCropGrowInfo(activityId,cropId)
	if not self.cropList then 
		self.cropList = {}
		local activityCfg = gModelActivity:GetWebActivityDataById(activityId)
		if activityCfg and activityCfg.config then 
			local crops = string.split(activityCfg.config.rankItem,";")
			for _, crop in ipairs(crops) do
				local cropArr = string.split(crop,"=")
				
				self.cropList[tonumber(cropArr[1])] = {growTime =tonumber(cropArr[2]),count =tonumber(cropArr[3]),score =tonumber(cropArr[4]),steal=cropArr[5
				]}
			end
		end
	end
	local seedDat = cropId and self.cropList[cropId] or self.cropList
	return seedDat
end
--获取种子配置信息
function ModelFarm:GetSeedInfo(activityId,seedId)
	if not self.seedList then 
		self.seedList = {}
		local activityCfg = gModelActivity:GetWebActivityDataById(activityId)
		local seedItems = string.split(activityCfg.config.seedItem,";")
		for _, value in ipairs(seedItems) do
			local seedStr = string.split(value,"|")
			local cropArr = string.split(seedStr[2],",")
			if not self.seedList[tonumber(seedStr[1])] then self.seedList[tonumber(seedStr[1])] = {} end
			for _, crop in ipairs(cropArr) do
				local crops = string.split(crop,"=")
				self.seedList[tonumber(seedStr[1])][tonumber(crops[1])] = tonumber(crops[2])
			end
		end
	end
	if seedId then return self.seedList[seedId] end
	return self.seedList
end
--获取肥料配置信息
function ModelFarm:GetFertilizerInfo(sid)
	local activCfg = gModelActivity:GetWebActivityDataById(sid)
	local fertilizers = string.split(activCfg.config.fertilizerItem,"=")
	return {itemId = tonumber(fertilizers[1]),addTime = tonumber(fertilizers[2])}
end

--作物种植到成熟需要的肥料數量
function ModelFarm:CropNeedFertilizerNum(activityId,landIndex,time)
	local plyaerId = gModelPlayer:GetPlayerId()
	local farmData = self.farmList[plyaerId]
	local landInfo = farmData.lands[landIndex]
	local curTime = time or landInfo.starTime
	local remainTime = math.max(landInfo.endTime-curTime,0)
	local fertilizerItem = self:GetFertilizerInfo(activityId)
	local needCost = fertilizerItem and math.ceil(remainTime/fertilizerItem.addTime) or 0
	return needCost,fertilizerItem.itemId
end
--一键施肥
function ModelFarm:OneKeyFertilizerRed(activityId)
	local playerId = gModelPlayer:GetPlayerId()
	local farmInfo = self.farmList[playerId]
	local curTime = GetTimestamp()
	local totalCost = 0
	local itemId = 0
	for indx, landInfo in pairs(farmInfo.lands) do
		if not landInfo:IsMatureCrop() then --没成熟
			local costNum ,costId = self:CropNeedFertilizerNum(activityId,indx,curTime)
			totalCost = totalCost+costNum
			itemId = costId 
		end
	end
	local curCount = gModelItem:GetNumByRefId(itemId)
	local oneKeyFertilizer = totalCost>0 and totalCost<=curCount
	return oneKeyFertilizer,totalCost,itemId
end

--作物是否成熟
function ModelFarm:CropMatureRed()
	local playerId = gModelPlayer:GetPlayerId()
	local farmInfo = self.farmList[playerId]
	if not farmInfo then return false end
	for _, landInfo in pairs(farmInfo.lands or {}) do
		if landInfo:IsMatureCrop() then 
			return true
		end
	end
	return false
end
--是否可激活狗巡逻
function ModelFarm:ActivateDogRed(activityId)
	local activCfg = gModelActivity:GetWebActivityDataById(activityId)
	if not activCfg or not activCfg.config then return false end
	local playerId = gModelPlayer:GetPlayerId()
	local farmInfo = self.farmList[playerId]
	if not farmInfo then return false end
	local canActiveTime = activCfg.config.DogRestTimes+farmInfo.patrolDogTime
	return canActiveTime <= GetTimestamp()
end
--掉落積分紅點
function ModelFarm:DropScoreRed()
	local playerId = gModelPlayer:GetPlayerId()
	local farmInfo = self.farmList[playerId]
	if not farmInfo then return false end
	return farmInfo.dropScore>0
end
--戰令紅點
function ModelFarm:ZhanlingRed(activityId)
	local activCfg = gModelActivity:GetWebActivityDataById(activityId)
	if not activCfg or not activCfg.config then return false end
	local pagePara = gModelFunctionOpen:ModifyWndPara(activCfg.config.jump)
	local subPage = pagePara.subPage or 0
	local zhanlingId = gModelActivity:GetSidByUniqueJump(subPage) or 0
	local isRed = gModelRedPoint:GetActRedPointMap(zhanlingId)
	return isRed and true or false
end

return ModelFarm